CREATE OR REPLACE TEMPORARY TABLE mp_probe AS SELECT CASE WHEN (lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND demo_health.dbo.episodes.loaded_at IS NOT NULL AND date_diff('day', lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) >= $1) THEN CAST(date_trunc('month', lk.lk_referral_date) AS DATE) ELSE NULL END AS event_month, CASE WHEN (lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND demo_health.dbo.episodes.loaded_at IS NOT NULL AND date_diff('day', lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) >= $1 AND date_diff('day', lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) > $2) THEN $3 WHEN (lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND demo_health.dbo.episodes.loaded_at IS NOT NULL AND date_diff('day', lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) >= $1 AND date_diff('day', lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) < $4) THEN $5 WHEN (lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND demo_health.dbo.episodes.loaded_at IS NOT NULL AND date_diff('day', lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) >= $1) THEN date_diff('day', lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) ELSE NULL END AS lag_day, CAST(demo_health.dbo.episodes.loaded_at AS DATE) AS load_epoch_day, CAST(NULL AS VARCHAR) AS batch_id, CAST(NULL AS VARCHAR) AS alt_value, CASE WHEN (lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND demo_health.dbo.episodes.loaded_at IS NOT NULL AND date_diff('day', lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) >= $1) THEN $6 ELSE $7 END AS is_eligible, CASE WHEN (lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NULL) THEN $8 ELSE $9 END AS is_null_event_time, CASE WHEN (lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND demo_health.dbo.episodes.loaded_at IS NULL) THEN $10 ELSE $11 END AS is_null_load_time_only, CASE WHEN (lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND demo_health.dbo.episodes.loaded_at IS NOT NULL AND date_diff('day', lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) >= $12 AND date_diff('day', lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) < $13) THEN $14 ELSE $15 END AS is_negative_clipped, CASE WHEN (lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND demo_health.dbo.episodes.loaded_at IS NOT NULL AND date_diff('day', lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) < $16) THEN $17 ELSE $18 END AS is_negative_lag_excluded, CASE WHEN (lk.lk_matched IS NOT NULL AND lk.lk_referral_date IS NOT NULL AND demo_health.dbo.episodes.loaded_at IS NOT NULL AND date_diff('day', lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) >= $1 AND date_diff('day', lk.lk_referral_date, demo_health.dbo.episodes.loaded_at) > $19) THEN $20 ELSE $21 END AS is_overflow, CASE WHEN (lk.lk_matched IS NULL) THEN $22 ELSE $23 END AS is_join_unmatched, CASE WHEN (lk.lk_matched IS NULL OR lk.lk_rn = $24) THEN $25 ELSE $26 END AS is_base_row, CASE WHEN (lk.lk_rn = $27 AND lk.lk_dup > $28) THEN $29 ELSE $30 END AS is_ambiguous_base, lk.lk_dup AS lookup_dup, CAST(NULL AS VARCHAR) AS key_hash, demo_health.dbo.episodes.loaded_at AS load_time 
FROM demo_health.dbo.episodes LEFT OUTER JOIN (SELECT demo_health.dbo.referrals.id AS lk_id, demo_health.dbo.referrals.referral_date AS lk_referral_date, demo_health.dbo.referrals.site AS lk_site, $31 AS lk_matched, count(*) OVER (PARTITION BY demo_health.dbo.referrals.id, demo_health.dbo.referrals.site) AS lk_dup, row_number() OVER (PARTITION BY demo_health.dbo.referrals.id, demo_health.dbo.referrals.site ORDER BY demo_health.dbo.referrals.id, demo_health.dbo.referrals.site) AS lk_rn 
FROM demo_health.dbo.referrals) AS lk ON demo_health.dbo.episodes.referral_id = lk.lk_id AND demo_health.dbo.episodes.site_code = lk.lk_site 
WHERE demo_health.dbo.episodes.loaded_at <= $32 OR demo_health.dbo.episodes.loaded_at IS NULL
